using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public class TicketPredictionResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Probabilities { get; set; } = new();
}

public class EvaluationMetricsResponse
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
    public PerClassMetric[] PerClassMetrics { get; set; } = [];
}

public class PerClassMetric
{
    public string Class { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly MulticlassClassificationMetrics _metrics;
    private readonly VBuffer<ReadOnlyMemory<char>> _labelBuffer;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);

        IDataView dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(dataView, testFraction: 0.3);

        // Combine Subject + Description into a single text feature, then featurize alongside Priority
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _model = pipeline.Fit(split.TrainSet);
        _metrics = _mlContext.MulticlassClassification.Evaluate(
            _model.Transform(split.TestSet), labelColumnName: "Label");

        // Cache label names for probability mapping
        var labelCol = _model.GetOutputSchema(split.TrainSet.Schema)["Label"];
        labelCol.GetKeyValues(ref _labelBuffer);

        _predictionEngine = _mlContext.Model
            .CreatePredictionEngine<TicketData, TicketPrediction>(_model);
    }

    public TicketPredictionResponse Predict(TicketRequest request)
    {
        var prediction = _predictionEngine.Predict(new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        });

        var labels = _labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();
        var probabilities = new Dictionary<string, float>();
        for (int i = 0; i < labels.Length && i < prediction.Score.Length; i++)
            probabilities[labels[i]] = prediction.Score[i];

        return new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Probabilities = probabilities
        };
    }

    public EvaluationMetricsResponse GetMetrics()
    {
        var labels = _labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();
        var perClass = new List<PerClassMetric>();
        for (int i = 0; i < labels.Length; i++)
        {
            perClass.Add(new PerClassMetric
            {
                Class = labels[i],
                Precision = i < _metrics.PerClassPrecision.Count ? _metrics.PerClassPrecision[i] : 0,
                Recall = i < _metrics.PerClassRecall.Count ? _metrics.PerClassRecall[i] : 0,
                F1Score = i < _metrics.PerClassPrecision.Count && i < _metrics.PerClassRecall.Count
                    ? 2 * _metrics.PerClassPrecision[i] * _metrics.PerClassRecall[i]
                      / (_metrics.PerClassPrecision[i] + _metrics.PerClassRecall[i] + 1e-10)
                    : 0
            });
        }

        return new EvaluationMetricsResponse
        {
            MacroAccuracy = _metrics.MacroAccuracy,
            MicroAccuracy = _metrics.MicroAccuracy,
            LogLoss = _metrics.LogLoss,
            LogLossReduction = _metrics.LogLossReduction,
            PerClassMetrics = perClass.ToArray()
        };
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketsController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        return Ok(_classifier.Predict(request));
    }

    [HttpGet("metrics")]
    public ActionResult<EvaluationMetricsResponse> GetMetrics()
    {
        return Ok(_classifier.GetMetrics());
    }
}

