public EvaluationMetricsResponse GetMetrics()
{
    var labels = _labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();
    var cm = _metrics.ConfusionMatrix;
    var perClass = new List<PerClassMetric>();
    for (int i = 0; i < labels.Length; i++)
    {
        var precision = i < cm.PerClassPrecision.Count ? Sanitize(cm.PerClassPrecision[i]) : 0;
        var recall = i < cm.PerClassRecall.Count ? Sanitize(cm.PerClassRecall[i]) : 0;
        var denom = precision + recall;
        perClass.Add(new PerClassMetric
        {
            Class = labels[i],
            Precision = precision,
            Recall = recall,
            F1Score = denom > 0 ? 2 * precision * recall / denom : 0
        });
    }

    return new EvaluationMetricsResponse
    {
        MacroAccuracy = Sanitize(_metrics.MacroAccuracy),
        MicroAccuracy = Sanitize(_metrics.MicroAccuracy),
        LogLoss = Sanitize(_metrics.LogLoss),
        LogLossReduction = Sanitize(_metrics.LogLossReduction),
        PerClassMetrics = perClass.ToArray()
    };
}

private static double Sanitize(double value) =>
    double.IsNaN(value) || double.IsInfinity(value) ? 0 : value;

